content.problemStatement:
What will be the output of the following C++ code?

```cpp
#include 
using namespace std;

int main() {
    int a = 5, b = 5;

    int result1 = ++a * 3; 
    int result2 = b++ * 3; 

    cout << "Pre-increment result: " << result1 << endl;
    cout << "Post-increment result: " << result2 << endl;
    cout << "Final value of a: " << a << endl;
    cout << "Final value of b: " << b << endl;

    return 0;
}
```

